// ship rotation sample
if (keys['ArrowLeft']) ship.angle -= 0.05;
if (keys['ArrowRight']) ship.angle += 0.05;
if (keys['ArrowUp']) {
  ship.vx += Math.cos(ship.angle) * 0.1;
  ship.vy += Math.sin(ship.angle) * 0.1;
}
ship.vx *= 0.98; ship.vy *= 0.98;

// input-buffering pattern
let pendingDir = currentDir;
function tryTurn() {
  if (canMove(player.x, player.y, pendingDir)) currentDir = pendingDir;
}
// each tick, apply currentDir if not blocked, else stop.

// log-floating logic
if (player.row === RIVER_ROW) {
  const log = logs.find(l => l.row === player.row && Math.abs(l.x - player.x) < TILE);
  if (log) { player.x += log.vx; }  // float with the log
  else { loseLife(); }  // fell in water
}

// line-clear pattern
for (let row = HEIGHT - 1; row >= 0; row--) {
  if (playfield[row].every(cell => cell !== 0)) {
    playfield.splice(row, 1);
    playfield.unshift(new Array(WIDTH).fill(0));
    linesCleared++;
    row++;  // recheck same index after splice
  }
}

// paddle-bounce angle
const paddleHitX = (ball.x - paddle.x) / paddle.width; // 0..1
const angle = (paddleHitX - 0.5) * Math.PI * 0.7; // -63°..+63°
ball.vx = Math.sin(angle) * BALL_SPEED;
ball.vy = -Math.abs(Math.cos(angle) * BALL_SPEED);

// Lego: import { PongAI } from '../../entities/PongAI.js';
const ai = new PongAI({ paddle: cpu, ball, bounds: { minY: 0, maxY: H - cpu.height }, delay: 110, error: 0.12 });
// in game loop: ai.update(dt);

// Non-Lego inline equivalent:
let aiTarget = ball.y, aiLastDecision = 0;
function updateAI(dt, now) { if (now - aiLastDecision > 110) { aiTarget = ball.y + (Math.random() - 0.5) * cpu.height * 0.24; aiLastDecision = now; } if (cpu.y + cpu.height/2 < aiTarget - 8) cpu.y += AI_SPEED * dt; else if (cpu.y + cpu.height/2 > aiTarget + 8) cpu.y -= AI_SPEED * dt; }

// minimax AI
function minimax(board, isMaxTurn) {
  const winner = checkWin(board);
  if (winner === 'O') return 1;  // AI wins
  if (winner === 'X') return -1; // Player wins
  if (isFull(board)) return 0;
  // ... recurse, pick max/min
}

// closest-in-range targeting
function pickTarget(tower, enemies) {
  return enemies
    .filter(e => dist(tower, e) <= tower.range)
    .sort((a, b) => b.pathProgress - a.pathProgress)[0]; // most-progressed first
}
